let input;
try { input = JSON.parse(query); } catch(e) { input = {action:'list'}; }
const apiKey = '{{N8N_API_KEY}}';
const hdrs = {'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json'};
let result;
if (input.action === 'list') {
  result = await helpers.httpRequest({method:'GET', url:'{{N8N_INTERNAL_URL}}/api/v1/workflows', headers: hdrs});
} else if (input.action === 'get' && input.workflowId) {
  result = await helpers.httpRequest({method:'GET', url:'{{N8N_INTERNAL_URL}}/api/v1/workflows/'+input.workflowId, headers: hdrs});
} else {
  return JSON.stringify({error: 'Use action: list or get'});
