const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';

async function pgrest(method, path, body, extraHeaders = {}) {
  const opts = {
    method,
    url: `${SUPABASE_URL}${path}`,
    headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json', ...extraHeaders },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };
  if (body) opts.body = JSON.stringify(body);
  const res = await helpers.httpRequest(opts);
  if (!res.body || res.body === '') return null;
  return typeof res.body === 'string' ? JSON.parse(res.body) : res.body;
}

let input;
try { input = JSON.parse(query); } catch(e) { return 'Error: invalid JSON. Expected: {"action":"list|read|create|update|archive", ...}'; }

const action = input.action;

if (action === 'list') {
  const projects = await pgrest('GET', '/rest/v1/projects?order=updated_at.desc&select=name,status,updated_at');
  if (!projects || projects.length === 0) return JSON.stringify({ projects: [], message: 'No projects yet.' });
  return JSON.stringify({ projects });

} else if (action === 'read') {
  if (!input.name) return 'Error: name is required';
  const projects = await pgrest('GET', `/rest/v1/projects?name=eq.${encodeURIComponent(input.name)}&select=name,status,content,created_at,updated_at`);
  if (!projects || projects.length === 0) return JSON.stringify({ error: 'Project not found: ' + input.name });
  return JSON.stringify(projects[0]);

} else if (action === 'create') {
  if (!input.name) return 'Error: name is required';
  const body = { name: input.name, content: input.content || '', status: 'active' };
  const result = await pgrest('POST', '/rest/v1/projects', body, { 'Prefer': 'return=representation' });
  if (result && result.code) return JSON.stringify({ error: result.message || 'Create failed' });
  return JSON.stringify({ success: true, project: Array.isArray(result) ? result[0] : result });

} else if (action === 'update') {
  if (!input.name) return 'Error: name is required';
  if (input.content === undefined) return 'Error: content is required';
  const body = { content: input.content, updated_at: new Date().toISOString() };
  if (input.status) body.status = input.status;
  const result = await pgrest('PATCH', `/rest/v1/projects?name=eq.${encodeURIComponent(input.name)}`, body, { 'Prefer': 'return=representation' });
  if (!result || result.length === 0) return JSON.stringify({ error: 'Project not found: ' + input.name });
  return JSON.stringify({ success: true, project: Array.isArray(result) ? result[0] : result });

} else if (action === 'archive') {
  if (!input.name) return 'Error: name is required';
  const body = { status: 'completed', updated_at: new Date().toISOString() };
  const result = await pgrest('PATCH', `/rest/v1/projects?name=eq.${encodeURIComponent(input.name)}`, body, { 'Prefer': 'return=representation' });
  if (!result || result.length === 0) return JSON.stringify({ error: 'Project not found: ' + input.name });
  return JSON.stringify({ success: true, archived: input.name });

} else {
  return 'Error: unknown action "' + action + '". Use: list, read, create, update, archive';
}

parameters.description:
Delegate a task to a specialized expert agent. The expert works independently with its own AI model and tools, then returns a structured result. You should rephrase the result in your own tone before replying to the user.

Parameters (JSON):
- agent: Expert agent identifier (e.g. "research-expert", "content-creator", "data-analyst")
- task: Detailed task description — be specific about what you need
- context: Relevant conversation context the expert should know (optional)

Examples:
{"agent":"research-expert","task":"Recherchiere die besten Wanderwege in Tirol mit Schwierigkeitsgrad und Länge","context":"User plant einen Wanderurlaub im Sommer"}
{"agent":"content-creator","task":"Erstelle einen Instagram-Post über unser neues Produkt","context":"Produkt: AI-gestützter Kalender, Zielgruppe: junge Berufstätige"}
{"agent":"data-analyst","task":"Analysiere diese Verkaufszahlen und erstelle einen Report","context":"Q1 2026: Jan 45k, Feb 52k, Mär 61k"}

